Eigen::MatrixXd EM(p,p);

// Copy data into STL vector and Eigen dynamic matrix
for (int i=0; i<p; ++i){
    for (int j=0; j<p; ++j){
        EM(i,j) = V[i + j*p] = X(i,j);
    }
}

double tran = 0.0;

for (int i=0; i<p; ++i){
    for (int j=0; j<p; ++j){
        for (int k=0; k<p; ++k){
            if ((j != i) && (k != i) && (j != k)) {
                tran += V[i + j*p]*V[j + k*p]*V[i + k*p];
            }
        }
    }
}

return Rcpp::wrap(tran);
'
stl<-cxxfunction(
    signature(
    mat="numeric"
    ),
    body=STLvectortest,
    includes=header,
    plugin="RcppEigen",
    verbose=T
    )

Reigentest<-'
