    }
}

double tran = 0.0;

for (int i=0; i<p; ++i){
    for (int j=0; j<p; ++j){
        for (int k=0; k<p; ++k){
            if ((j != i) && (k != i) && (j != k)) {
                tran += EM(i,j)*EM(j,k)*EM(i,k);
            }
        }
    }
}

return Rcpp::wrap(tran);
'
eig<-cxxfunction(
    signature(
    mat="numeric"
    ),
    body=Reigentest,
    includes=header,
    plugin="RcppEigen",
    verbose=T
    )

Rcppbase<-'
const NumericMatrix X = Rcpp::as<NumericMatrix>(mat);
int p = X.nrow();
std::vector<double> V(p*p);
Eigen::MatrixXd EM(p,p);
// Copy data into STL vector and Eigen dynamic matrix
for (int i=0; i<p; ++i){
    for (int j=0; j<p; ++j){
        EM(i,j) = V[i + j*p] = X(i,j);
    }
}

double tran = 0.0;

return Rcpp::wrap(tran);
'
rcppbase<-cxxfunction(
    signature(
    mat="numeric"
    ),
    body=Rcppbase,
    includes=header,
    plugin="RcppEigen",
    settings=settings,
    verbose=T
    )

